package com.example.oauthclient;

import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.util.UriComponentsBuilder;

import jakarta.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.net.URI;

@SpringBootApplication
public class OAuthClientApplication {

    public static void main(String[] args) {
        SpringApplication.run(OAuthClientApplication.class, args);
    }
}

@Controller
class OAuthController {

    private static final String AUTHORIZATION_ENDPOINT = "https://auth-server.example.com/oauth2/authorize";
    private static final String CLIENT_ID = "your-client-id";
    private static final String REDIRECT_URI = "http://localhost:8080/oauth/callback";
    private static final String SCOPE = "openid profile email";
    private static final String RESPONSE_TYPE = "code";

    @GetMapping("/oauth/login")
    public void login(HttpServletResponse response) throws IOException {
        String authorizationUrl = UriComponentsBuilder
                .fromHttpUrl(AUTHORIZATION_ENDPOINT)
                .queryParam("client_id", CLIENT_ID)
                .queryParam("redirect_uri", REDIRECT_URI)
                .queryParam("scope", SCOPE)
                .queryParam("response_type", RESPONSE_TYPE)
                .build(true)
                .toUriString();

        response.sendRedirect(authorizationUrl);
    }

    @GetMapping("/oauth/callback")
    public ResponseEntity<String> callback(@RequestParam(required = false) String code,
                                           @RequestParam(required = false) String error) {
        if (error != null) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED)
                    .body("Authorization failed: " + error);
        }

        if (code == null || code.isBlank()) {
            return ResponseEntity.badRequest().body("Missing authorization code");
        }

        return ResponseEntity.ok("Authorization code received: " + code);
    }
}